import React, { useEffect, useState, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { ENDPOINTS } from '../api';

type DeliveryAddress = string | { address: string; latitude?: number; longitude?: number };

function getAddressStr(addr?: DeliveryAddress): string {
  if (!addr) return '';
  if (typeof addr === 'object') return addr.address || '';
  return addr;
}

interface RouteStop {
  order_id: string;
  delivery_address?: DeliveryAddress;
  district?: string;
  priority?: string;
  status?: string;
  estimated_distance?: number;
}

interface RouteData {
  driver_id: string;
  total_distance?: number;
  stops: RouteStop[];
  optimized_at?: string;
}

const PRIORITY_COLORS: Record<string, { bg: string; text: string }> = {
  high:   { bg: '#fee2e2', text: '#dc2626' },
  medium: { bg: '#fef9c3', text: '#92400e' },
  low:    { bg: '#dcfce7', text: '#166534' },
};

export default function RoutePage() {
  const { user, token } = useAuth();
  const [route, setRoute] = useState<RouteData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchRoute = useCallback(async () => {
    if (!user?.driver_id) { setError('Driver ID not found'); setLoading(false); return; }
    setError('');
    try {
      const res = await fetch(ENDPOINTS.optimizeRoute(user.driver_id), {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to load route');
      // ROS returns { route: [...], total_distance_km, ... }
      // Filter to delivery stops only and remap field names
      const stops = Array.isArray(data.route)
        ? data.route
            .filter((s: any) => s.type === 'delivery')
            .map((s: any) => ({
              order_id: s.order_id,
              delivery_address: s.address,
              district: s.district,
              priority: s.priority,
              status: s.status,
              estimated_distance: s.distance_from_previous,
            }))
        : [];
      setRoute({
        driver_id: data.driver_id,
        total_distance: data.total_distance_km,
        optimized_at: data.optimized_at,
        stops,
      });
    } catch (err: any) {
      setError(err.message);
    } finally { setLoading(false); }
  }, [user?.driver_id, token]);

  useEffect(() => { fetchRoute(); }, [fetchRoute]);

  return (
    <div>
      <div style={{ background: '#fff', padding: '16px 20px', borderBottom: '1px solid #f1f5f9' }}>
        <div style={{ fontSize: 20, fontWeight: 800, color: '#0f172a' }}>My Route</div>
        <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 2 }}>Optimized delivery path</div>
      </div>

      <div style={{ padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 48, color: '#64748b' }}>Loading…</div>
        ) : error ? (
          <div style={{ textAlign: 'center', padding: 48 }}>
            <span className="material-icons-round" style={{ fontSize: 44, color: '#f59e0b', marginBottom: 10, display: 'block' }}>warning</span>
            <div style={{ fontSize: 14, color: '#64748b', marginBottom: 16 }}>{error}</div>
            <button onClick={fetchRoute} style={{
              background: '#0d9488', color: '#fff', border: 'none', borderRadius: 12,
              padding: '10px 20px', fontWeight: 600, fontSize: 14, cursor: 'pointer',
            }}>Try again</button>
          </div>
        ) : !route || !route.stops || route.stops.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 60 }}>
            <span className="material-icons-round" style={{ fontSize: 52, color: '#94a3b8', marginBottom: 14, display: 'block' }}>map</span>
            <div style={{ fontSize: 17, fontWeight: 700, color: '#475569' }}>No route yet</div>
            <div style={{ fontSize: 13, color: '#94a3b8', marginTop: 6 }}>Accept orders to see your optimized route</div>
          </div>
        ) : (
          <>
            {/* Summary */}
            <div style={{
              background: '#fff', borderRadius: 16, padding: 16, display: 'flex',
              justifyContent: 'space-around', marginBottom: 20, border: '1px solid #e2e8f0',
            }}>
              <SummaryItem value={String(route.stops.length)} label="Stops" />
              {route.total_distance != null && (
                <SummaryItem value={`${route.total_distance.toFixed(1)} km`} label="Total distance" />
              )}
              {route.optimized_at && (
                <SummaryItem
                  value={new Date(route.optimized_at).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}
                  label="Last updated"
                />
              )}
            </div>

            <div style={{ fontSize: 14, fontWeight: 700, color: '#475569', marginBottom: 12 }}>Delivery Stops</div>

            {route.stops.map((stop, idx) => {
              const pc = stop.priority ? PRIORITY_COLORS[stop.priority] : null;
              return (
                <div key={stop.order_id} style={{ display: 'flex', marginBottom: 4 }}>
                  {/* Timeline indicator */}
                  <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginRight: 12, width: 28 }}>
                    <div style={{
                      width: 28, height: 28, borderRadius: 14, background: '#0d9488',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      color: '#fff', fontWeight: 800, fontSize: 12,
                    }}>{idx + 1}</div>
                    {idx < route.stops.length - 1 && (
                      <div style={{ width: 2, flex: 1, background: '#e2e8f0', minHeight: 12, margin: '2px 0' }} />
                    )}
                  </div>

                  {/* Stop card */}
                  <div style={{
                    flex: 1, background: '#fff', borderRadius: 14, padding: 12,
                    marginBottom: 8, border: '1px solid #f1f5f9',
                  }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                      <span style={{ fontSize: 13, fontWeight: 700, color: '#0f172a' }}>#{stop.order_id?.slice(-6)}</span>
                      {pc && (
                        <span style={{
                          background: pc.bg, color: pc.text,
                          fontSize: 10, fontWeight: 700, padding: '2px 8px', borderRadius: 10,
                          textTransform: 'capitalize',
                        }}>{stop.priority}</span>
                      )}
                    </div>
                    <div style={{ fontSize: 12, color: '#64748b', lineHeight: '16px' }}>
                      {getAddressStr(stop.delivery_address) || stop.district || '—'}
                    </div>
                    {stop.estimated_distance != null && (
                      <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 4 }}>
                        <span className="material-icons-round" style={{ fontSize: 12, verticalAlign: 'middle' }}>place</span>{' '}{stop.estimated_distance.toFixed(1)} km from prev.
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </>
        )}
      </div>
    </div>
  );
}

function SummaryItem({ value, label }: { value: string; label: string }) {
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{ fontSize: 18, fontWeight: 800, color: '#0d9488' }}>{value}</div>
      <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 2 }}>{label}</div>
    </div>
  );
}
